"use client"

import { FileText, Calendar } from "lucide-react"
import type { Aporte, Actividad } from "@/lib/types"
import { format, parseISO } from "date-fns"
import { es } from "date-fns/locale"

interface RecentActivityFeedProps {
  aportes: Aporte[]
  actividades: Actividad[]
}

export function RecentActivityFeed({
  aportes,
  actividades,
}: RecentActivityFeedProps) {
  const sorted = [...aportes]
    .sort(
      (a, b) =>
        new Date(b.creadoEn).getTime() - new Date(a.creadoEn).getTime()
    )
    .slice(0, 5)

  if (sorted.length === 0) {
    return (
      <p className="py-8 text-center text-sm text-muted-foreground">
        No hay aportes recientes
      </p>
    )
  }

  return (
    <div className="flex flex-col gap-0">
      {sorted.map((aporte, idx) => {
        const actividad = actividades.find(
          (a) => a.id === aporte.actividadId
        )
        return (
          <div
            key={aporte.id}
            className={`flex gap-3 px-1 py-3 ${
              idx < sorted.length - 1 ? "border-b border-border" : ""
            }`}
          >
            <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-md bg-primary/10">
              <FileText className="h-4 w-4 text-primary" />
            </div>
            <div className="flex min-w-0 flex-1 flex-col gap-0.5">
              <p className="truncate text-sm font-medium text-foreground">
                {actividad ? `Act. ${actividad.numero}: ${actividad.titulo}` : "Actividad"}
              </p>
              <p className="line-clamp-2 text-xs text-muted-foreground">
                {aporte.descripcion}
              </p>
              <div className="mt-1 flex items-center gap-1 text-xs text-muted-foreground/70">
                <Calendar className="h-3 w-3" />
                <span>
                  {format(parseISO(aporte.fecha), "d 'de' MMMM, yyyy", {
                    locale: es,
                  })}
                </span>
              </div>
            </div>
          </div>
        )
      })}
    </div>
  )
}
