"use client"

import { Building2, Calendar, User, Hash } from "lucide-react"
import type { Contrato, Configuracion } from "@/lib/types"
import { format, parseISO, differenceInDays } from "date-fns"
import { es } from "date-fns/locale"

interface ContractSummaryCardProps {
  contrato: Contrato
  configuracion: Configuracion
}

export function ContractSummaryCard({
  contrato,
  configuracion,
}: ContractSummaryCardProps) {
  const diasRestantes = differenceInDays(
    parseISO(contrato.fechaFin),
    new Date()
  )
  const diasTotales = differenceInDays(
    parseISO(contrato.fechaFin),
    parseISO(contrato.fechaInicio)
  )
  const progreso = Math.max(
    0,
    Math.min(100, ((diasTotales - diasRestantes) / diasTotales) * 100)
  )

  return (
    <div className="flex flex-col gap-4 rounded-lg border border-border bg-card p-5">
      <div className="flex items-center gap-2">
        <div className="flex h-9 w-9 items-center justify-center rounded-md bg-primary/10">
          <Building2 className="h-4.5 w-4.5 text-primary" />
        </div>
        <div>
          <h3 className="text-sm font-semibold text-card-foreground">
            Resumen del Contrato
          </h3>
          <p className="text-xs text-muted-foreground">{contrato.numero}</p>
        </div>
      </div>

      <div className="flex flex-col gap-3">
        <div className="flex items-start gap-2">
          <Hash className="mt-0.5 h-3.5 w-3.5 shrink-0 text-muted-foreground" />
          <div>
            <p className="text-xs font-medium text-muted-foreground">Entidad</p>
            <p className="text-sm text-card-foreground">{contrato.entidad}</p>
          </div>
        </div>
        <div className="flex items-start gap-2">
          <User className="mt-0.5 h-3.5 w-3.5 shrink-0 text-muted-foreground" />
          <div>
            <p className="text-xs font-medium text-muted-foreground">Contratista</p>
            <p className="text-sm text-card-foreground">
              {contrato.contratistaNombre}
            </p>
          </div>
        </div>
        <div className="flex items-start gap-2">
          <Calendar className="mt-0.5 h-3.5 w-3.5 shrink-0 text-muted-foreground" />
          <div>
            <p className="text-xs font-medium text-muted-foreground">Vigencia</p>
            <p className="text-sm text-card-foreground">
              {format(parseISO(contrato.fechaInicio), "d MMM yyyy", {
                locale: es,
              })}{" "}
              -{" "}
              {format(parseISO(contrato.fechaFin), "d MMM yyyy", {
                locale: es,
              })}
            </p>
          </div>
        </div>
      </div>

      <div className="flex flex-col gap-1.5">
        <div className="flex items-center justify-between text-xs">
          <span className="text-muted-foreground">Avance del contrato</span>
          <span className="font-medium text-card-foreground">
            {Math.round(progreso)}%
          </span>
        </div>
        <div className="h-2 w-full overflow-hidden rounded-full bg-muted">
          <div
            className="h-full rounded-full bg-primary transition-all"
            style={{ width: `${progreso}%` }}
          />
        </div>
        <p className="text-xs text-muted-foreground">
          {diasRestantes > 0
            ? `${diasRestantes} dias restantes`
            : "Contrato finalizado"}
        </p>
      </div>

      <div className="rounded-md bg-muted/60 px-3 py-2">
        <p className="text-xs font-medium text-muted-foreground">
          Periodo actual de informe
        </p>
        <p className="text-sm font-medium text-card-foreground">
          {format(
            parseISO(configuracion.periodoActualInicio),
            "d MMM",
            { locale: es }
          )}{" "}
          -{" "}
          {format(
            parseISO(configuracion.periodoActualFin),
            "d MMM yyyy",
            { locale: es }
          )}
        </p>
      </div>
    </div>
  )
}
