"use client"

import {
  ClipboardList,
  FileCheck,
  ImageIcon,
  CalendarClock,
} from "lucide-react"
import { PageHeader } from "@/components/page-header"
import { KpiCard } from "@/components/kpi-card"
import { ActivityProgressChart } from "@/components/activity-progress-chart"
import { RecentActivityFeed } from "@/components/recent-activity-feed"
import { ContractSummaryCard } from "@/components/contract-summary-card"
import {
  getActividades,
  getAportes,
  getEvidencias,
  getContrato,
  getConfiguracion,
} from "@/lib/store"
import { differenceInDays, parseISO } from "date-fns"

export default function DashboardPage() {
  const actividades = getActividades()
  const aportes = getAportes()
  const evidencias = getEvidencias()
  const contrato = getContrato()
  const configuracion = getConfiguracion()

  const diasRestantes = Math.max(
    0,
    differenceInDays(parseISO(contrato.fechaFin), new Date())
  )

  return (
    <div className="flex flex-col gap-6">
      <PageHeader
        titulo="Dashboard"
        descripcion={`Contrato ${contrato.numero} - ${contrato.entidad}`}
      />

      <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4">
        <KpiCard
          titulo="Total Actividades"
          valor={actividades.length}
          descripcion="Actividades contractuales"
          icon={ClipboardList}
        />
        <KpiCard
          titulo="Aportes Registrados"
          valor={aportes.length}
          descripcion="En el periodo actual"
          icon={FileCheck}
        />
        <KpiCard
          titulo="Evidencias Cargadas"
          valor={evidencias.length}
          descripcion="Archivos de soporte"
          icon={ImageIcon}
        />
        <KpiCard
          titulo="Dias Restantes"
          valor={diasRestantes}
          descripcion="Hasta fin de contrato"
          icon={CalendarClock}
        />
      </div>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
        <div className="flex flex-col gap-6 lg:col-span-2">
          <div className="rounded-lg border border-border bg-card p-5">
            <h2 className="mb-4 text-sm font-semibold text-card-foreground">
              Aportes por Actividad
            </h2>
            <ActivityProgressChart
              actividades={actividades}
              aportes={aportes}
            />
          </div>

          <div className="rounded-lg border border-border bg-card p-5">
            <h2 className="mb-2 text-sm font-semibold text-card-foreground">
              Actividad Reciente
            </h2>
            <RecentActivityFeed
              aportes={aportes}
              actividades={actividades}
            />
          </div>
        </div>

        <div className="lg:col-span-1">
          <ContractSummaryCard
            contrato={contrato}
            configuracion={configuracion}
          />
        </div>
      </div>
    </div>
  )
}
